# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
import json

def lambda_handler(event, context):
    # setup connection to the database
    conn = pymysql.connect(host='localhost', user='user', password='password', db='database')

    # setup empty sql query
    sql_query = 'SELECT * FROM products'

    # check event parameters and build SQL query
    if len(event) > 0:
        sql_query += ' WHERE '

        conditions = []
        for key, value in event.items():
            conditions.append(f"{key} = '{value}'")

        sql_query += ' AND '.join(conditions)

    # execute query
    with conn.cursor() as cursor:
        cursor.execute(sql_query)
        result = cursor.fetchall()

    conn.close()

    # return result to API as json
    return {
        'statusCode': 200,
        'body': json.dumps(result)
    }